features.snippet:
wire [2:0] z3;
wire [1:0] w3;
logic x3, y3;
// Bit-selects at indices 0, 1, and 2 all used as ref/output port connections
// Index 2 should produce extract_ref, not dyn_extract
MultiPorts p3(
  .a0(x3), .a1(y3),
  .v0(z3[2]),
  .v2(z3[0]),
  .c0(w3[1]),
  .v1(z3[1]),
  .c1(w3[0])
);

module MultiPorts(
  input  logic a0, a1,
  input  logic v0,
  output logic v1,
  output logic v2,
  input  logic c0,
  output logic c1
);
  assign v1 = v0;
  assign v2 = a0;
  assign c1 = a1 & c0;
endmodule
